```ps
# Get all local user accounts
$localUsers = Get-LocalUser

# Initialize a variable to keep track of whether a domain user was found
$domainUserFound = $false

# Loop through each local user account
foreach ($user in $localUsers) {
  # Check if the user account is a domain user
  if ($user.PrincipalSource -eq 'ActiveDirectory') {
      # A domain user was found
      $domainUserFound = $true

      # Print the user's account name
      Write-Host "Domain user found: $($user.Name)"
  }
}

# Check if a domain user was found
if ($domainUserFound) {
  Write-Host "A domain user was found."
} else {
  Write-Host "No domain users were found."
}
```

