function Get-Class {
	param (
		[Parameter(Mandatory = $true)]
		[string]$ClassName,

		[string]$Filter = $null,

		[ValidateSet("Stop", "Continue", "SilentlyContinue", "Inquire")]
		[string]$OnError = "Stop"
	)

	try {
		return Get-CimInstance -ClassName $ClassName -Filter $Filter -ErrorAction $OnError
	} catch {
		return Get-WmiObject -Class $ClassName -Filter $Filter -ErrorAction $OnError
	}
}
```

